/**
 * Named listener registry for simple pub/sub.
 */
export class ListenerList {
  /** @type {Map<string, (payload: unknown) => void>} */
  #listeners = new Map();

  /**
   * @param {string} name
   * @param {(payload: unknown) => void} listener
   */
  on(name, listener) {
    this.#listeners.set(name, listener);
  }

  /**
   * @param {string} name
   */
  off(name) {
    this.#listeners.delete(name);
  }

  /**
   * @param {unknown} payload
   */
  notify(payload) {
    for (const listener of this.#listeners.values()) {
      listener(payload);
    }
  }
}
